const express = require('express');
const app = express();
const productsRouter = express.Router();
const ordersRouter = express.Router();

productsRouter.get('/', (req, res) => { res.send('Liste des produits'); });
productsRouter.post('/', (req, res) => { res.send('Produit créé'); });
ordersRouter.post('/', (req, res) => { res.send('Commande créée'); });

app.use('/products', productsRouter);
app.use('/orders', ordersRouter);

app.get('/articles/:id/comments', (req, res) => {
  const articleId = req.params.id;
  let page = parseInt(req.query.page) || 1;
  let limit = parseInt(req.query.limit) || 10;
  const startIndex = (page - 1) * limit;
  const endIndex = page * limit;

  // Simulation des commentaires pour l'article
  const allComments = [
    { id: 1, text: 'Super article', articleId: '123' },
    { id: 2, text: 'Merci pour l\'info', articleId: '123' }
  ];

  const commentsForArticle = allComments.filter(c => c.articleId === articleId);
  const paginatedComments = commentsForArticle.slice(startIndex, endIndex);

  res.json({
    page,
    limit,
    total: commentsForArticle.length,
    data: paginatedComments
  });
});

